CREATE VIEW `ads_market_user_invite_friends_info_view` (`product_id` COMMENT "产品id", `id` COMMENT "自增id", `user_id` COMMENT "用户id", `jifen_num` COMMENT "积分总数", `type` COMMENT "1:有邀请阅读时长任务", `invite_user_id` COMMENT "被邀请人", `create_time` COMMENT "邀请时间")
COMMENT "阅读-邀请好友成功记录表" AS SELECT `ods`.`ods_tidb_readernovel_userinvitefriendsinfo`.`product_id`, `ods`.`ods_tidb_readernovel_userinvitefriendsinfo`.`id`, `ods`.`ods_tidb_readernovel_userinvitefriendsinfo`.`pid` AS `user_id`, `ods`.`ods_tidb_readernovel_userinvitefriendsinfo`.`jifennum` AS `jifen_num`, `ods`.`ods_tidb_readernovel_userinvitefriendsinfo`.`type`, `ods`.`ods_tidb_readernovel_userinvitefriendsinfo`.`inviteuserid` AS `invite_user_id`, `ods`.`ods_tidb_readernovel_userinvitefriendsinfo`.`createtime` AS `create_tm`
FROM `ods`.`ods_tidb_readernovel_userinvitefriendsinfo`;